sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    var requesterField = 'requester';
    var msg = "Already 7 queries are present for this requester. Please delete any previous query then try to create a new one for this requester.";

    // Clear any previous message
    g_form.hideFieldMsg(requesterField, true);

    // If requester is empty, nothing to check
    if (!newValue) return;

    // Capture value to avoid race conditions
    var requestedValue = newValue;

    var ga = new GlideAjax('ChromaTechQueryLimitAjax');
    ga.addParam('sysparm_name', 'getRequesterQueryCount');
    ga.addParam('sysparm_requester_id', requestedValue);

    // Exclude current record (VERY important for updates)
    ga.addParam('sysparm_exclude_sys_id', g_form.getUniqueValue());

    ga.getXMLAnswer(function(answer) {

        // Ignore outdated responses
        if (g_form.getValue(requesterField) !== requestedValue)
            return;

        var count = parseInt((answer || '').toString().trim(), 10) || 0;

        if (count >= 7) {
            g_form.showFieldMsg(requesterField, msg, 'warning', true);
        } else {
            g_form.hideFieldMsg(requesterField, true);
        }
    });
}
